import{_ as s,n as a,v as n,ac as t}from"./chunks/framework.DFVDdn94.js";const i="/blog/essay/iterm2/iterm08.png",r="/blog/essay/iterm2/iterm01.png",p="/blog/essay/iterm2/iterm02.png",l="/blog/essay/iterm2/iterm03.png",o="/blog/essay/iterm2/iterm04.png",h="/blog/essay/iterm2/iterm05.png",c="/blog/essay/iterm2/iterm06.png",d="/blog/essay/iterm2/iterm07.png",z=JSON.parse('{"title":"iTerm2 + Oh-my-zh + p10k 终端美化","description":"iTerm2是终端的替代品，iTerm2将终端带入了现代时代，拥有你从未想过的一直想要的功能。","frontmatter":{"isTimeLine":true,"title":"iTerm2 + Oh-my-zh + p10k 终端美化","description":"iTerm2是终端的替代品，iTerm2将终端带入了现代时代，拥有你从未想过的一直想要的功能。","date":"2024-06-04T00:00:00.000Z","sticky":1,"tags":["工具"]},"headers":[],"relativePath":"_project/02-use-iterm2.md","filePath":"_project/02-use-iterm2.md","lastUpdated":1740995208000}'),m={name:"_project/02-use-iterm2.md"};function u(g,e,b,k,v,_){return n(),a("div",null,e[0]||(e[0]=[t('<h1 id="iterm2-oh-my-zh-p10k-终端美化" tabindex="-1">iTerm2 + Oh-my-zh + p10k 终端美化 <a class="header-anchor" href="#iterm2-oh-my-zh-p10k-终端美化" aria-label="Permalink to &quot;iTerm2 + Oh-my-zh + p10k 终端美化&quot;">​</a></h1><p><img src="'+i+'" alt="08"></p><h2 id="iterm2-下载" tabindex="-1">iterm2 下载 <a class="header-anchor" href="#iterm2-下载" aria-label="Permalink to &quot;iterm2 下载&quot;">​</a></h2><p><a href="https://iterm2.com/" target="_blank" rel="noreferrer">打开链接</a> 下载后解压即可。</p><h3 id="iterm2-设置" tabindex="-1">iterm2 设置 <a class="header-anchor" href="#iterm2-设置" aria-label="Permalink to &quot;iterm2 设置&quot;">​</a></h3><p>3.5.0 版本之后点击当前命令执行块会高亮边缘地区，这一点是很恶心的； Settings -&gt; General -&gt; Selection ...</p><p><img src="'+r+'" alt="01"></p><p>透明色，模糊，背景图，默认宽高设置 Settings -&gt; Profiles -&gt; Windows</p><p><img src="'+p+'" alt="02"></p><p>命令行背景色设置 Settings -&gt; Profiles -&gt; Colors</p><p><img src="'+l+'" alt="03"></p><p>状态栏设置 Settings -&gt; Profiles -&gt; Session</p><p><img src="'+o+`" alt="04"></p><h2 id="oh-my-zsh-下载" tabindex="-1">oh-my-zsh 下载 <a class="header-anchor" href="#oh-my-zsh-下载" aria-label="Permalink to &quot;oh-my-zsh 下载&quot;">​</a></h2><p>在<a href="https://github.com/ohmyzsh/ohmyzsh" target="_blank" rel="noreferrer">仓库</a> 中找到下载脚本，或者执行以下内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>sh -c &quot;$(curl -fsSL https://raw.githubusercontent.com/ohmyzsh/ohmyzsh/master/tools/install.sh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="zsh-syntax-highlighting-语法高亮插件" tabindex="-1">zsh-syntax-highlighting 语法高亮插件 <a class="header-anchor" href="#zsh-syntax-highlighting-语法高亮插件" aria-label="Permalink to &quot;zsh-syntax-highlighting 语法高亮插件&quot;">​</a></h3><p><a href="https://github.com/zsh-users/zsh-syntax-highlighting/blob/master/INSTALL.md" target="_blank" rel="noreferrer">仓库</a> 中找到下载脚本，或者执行以下内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>brew install zsh-syntax-highlighting</span></span>
<span class="line"><span>echo &quot;source $(brew --prefix)/share/zsh-syntax-highlighting/zsh-syntax-highlighting.zsh&quot; &gt;&gt; \${ZDOTDIR:-$HOME}/.zshrc</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 更新 ~/.zshrc 中插件的配置 </span></span>
<span class="line"><span>plugins=(git zsh-syntax-highlighting)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="zsh-autosuggestions-自动补全命令插件" tabindex="-1">zsh-autosuggestions 自动补全命令插件 <a class="header-anchor" href="#zsh-autosuggestions-自动补全命令插件" aria-label="Permalink to &quot;zsh-autosuggestions 自动补全命令插件&quot;">​</a></h3><p><a href="https://github.com/zsh-users/zsh-autosuggestions" target="_blank" rel="noreferrer">仓库</a> 中找到下载脚本，或者执行以下内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/zsh-users/zsh-autosuggestions \${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/plugins/zsh-autosuggestions</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 更新 ~/.zshrc 中插件的配置</span></span>
<span class="line"><span>plugins=( </span></span>
<span class="line"><span>    # other plugins...</span></span>
<span class="line"><span>    zsh-autosuggestions</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><code>source ~/.zshrc</code> 可能会出现如下错误： <code>no such file or directory： xxx</code>；参考 <a href="https://github.com/zsh-users/zsh-autosuggestions/issues/557" target="_blank" rel="noreferrer">这个</a>可能解决你的问题。</p><h2 id="powerlevel10k" tabindex="-1">powerlevel10k <a class="header-anchor" href="#powerlevel10k" aria-label="Permalink to &quot;powerlevel10k&quot;">​</a></h2><p>大家都喜欢直接叫 <code>p10k</code>，是一个 <code>zsh</code> 的主题，用来美化 terminal 窗口；<a href="https://github.com/romkatv/powerlevel10k?tab=readme-ov-file#meslo-nerd-font-patched-for-powerlevel10k" target="_blank" rel="noreferrer">仓库</a> 中找到下载脚本，或者执行以下内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>git clone --depth=1 https://github.com/romkatv/powerlevel10k.git \${ZSH_CUSTOM:-$HOME/.oh-my-zsh/custom}/themes/powerlevel10k</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者也可以通过 <code>home brew</code> 进行下载；</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>brew install powerlevel10k</span></span>
<span class="line"><span>echo &quot;source $(brew --prefix)/share/powerlevel10k/powerlevel10k.zsh-theme&quot; &gt;&gt;~/.zshrc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>brew</code>下载可能会报错，按照提示执行 <code>xcode-select --install</code> 即可</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span>Error: No developer tools installed.</span></span>
<span class="line"><span>Install the Command Line Tools:</span></span>
<span class="line"><span>  xcode-select --install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="p10k-配置" tabindex="-1">p10k 配置 <a class="header-anchor" href="#p10k-配置" aria-label="Permalink to &quot;p10k 配置&quot;">​</a></h3><p>在 <code>~/.zshrc</code> 中设置 <code>ZSH_THEME=&quot;powerlevel10k/powerlevel10k&quot;</code>，默认的 theme 是怎么忘记了；然后执行 <code>source ~/.zshrc</code> 生效修改的配置；随后即会出现配置命令行的提示；</p><p>一、提示下载字体，选择 <code>y</code>，可能会有点慢，下载完成后 <code>command + q</code> 关闭 terminal 重新启动；可以直接去 github 下载字体安装；<a href="https://github.com/ryanoasis/nerd-fonts/releases" target="_blank" rel="noreferrer">地址</a> 找到最新的 Hack.zip 下载后解压双击即可；这里就不用选择 <code>y</code> 了；</p><p><img src="`+h+'" alt="05"></p><p>下载完字体，使用 vscode 的同学需要把 vscode 的终端字体与 iterm2 保持一致。</p><p><img src="'+c+'" alt="06"></p><p>二、后面几步基本就是问你是否能看到图标、样式要什么样子的等等... 看着选就好了</p><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p>经过以上操作，terminal 的外观已经焕然一新了，当然大家如果喜欢折腾，相信还会有更好的方案；最终附上效果图</p><p><img src="'+d+'" alt="07"></p>',40)]))}const f=s(m,[["render",u]]);export{z as __pageData,f as default};
